import os
from cryptography.fernet import Fernet
import json

def generate_encryption_key():
    return Fernet.generate_key()

def get_encryption_key():
    config_file = 'app_config.json'
    if os.path.exists(config_file):
        with open(config_file, 'r') as f:
            config = json.load(f)
            return config.get('encryption_key', '').encode()
    
    key = generate_encryption_key()
    config = {'encryption_key': key.decode()}
    with open(config_file, 'w') as f:
        json.dump(config, f)
    return key

def encrypt_credit_card(card_number):
    key = get_encryption_key()
    cipher = Fernet(key)
    encrypted = cipher.encrypt(card_number.encode())
    return encrypted.decode()

def decrypt_credit_card(encrypted_card):
    key = get_encryption_key()
    cipher = Fernet(key)
    decrypted = cipher.decrypt(encrypted_card.encode())
    return decrypted.decode()

def mask_credit_card(card_number):
    if len(card_number) > 4:
        return '*' * (len(card_number) - 4) + card_number[-4:]
    return card_number

def process_transaction(card_number, amount):
    encrypted_card = encrypt_credit_card(card_number)
    masked_card = mask_credit_card(card_number)
    
    transaction_record = {
        'encrypted_card': encrypted_card,
        'masked_card': masked_card,
        'amount': amount
    }
    
    return transaction_record

def process_refund(encrypted_card):
    original_card = decrypt_credit_card(encrypted_card)
    return original_card